+// ─── Tile patterns for floor rendering ─────────────────────────────
+
+function drawStoneTile(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  // 16x16 gray stone block with mortar lines
+  ctx.fillStyle = '#7a7a7a'; // stone base
+  ctx.fillRect(x, y, 16, 16);
+  ctx.strokeStyle = '#a0a0a0'; // mortar lines
+  ctx.lineWidth = 1;
+  // horizontal mortar lines
+  ctx.beginPath();
+  ctx.moveTo(x, y + 5);
+  ctx.lineTo(x + 16, y + 5);
+  ctx.moveTo(x, y + 11);
+  ctx.lineTo(x + 16, y + 11);
+  // vertical mortar lines
+  ctx.moveTo(x + 5, y);
+  ctx.lineTo(x + 5, y + 16);
+  ctx.moveTo(x + 11, y);
+  ctx.lineTo(x + 11, y + 16);
+  ctx.stroke();
+}
+
+function drawWoodTile(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  // 16x16 horizontal wood planks with grain
+  const baseColor = '#a97456';
+  const plankColor = '#c28e5a';
+  ctx.fillStyle = baseColor;
+  ctx.fillRect(x, y, 16, 16);
+
+  ctx.strokeStyle = '#7a4f2a';
+  ctx.lineWidth = 1;
+  // Draw 3 horizontal plank lines
+  ctx.beginPath();
+  ctx.moveTo(x, y + 4);
+  ctx.lineTo(x + 16, y + 4);
+  ctx.moveTo(x, y + 8);
+  ctx.lineTo(x + 16, y + 8);
+  ctx.moveTo(x, y + 12);
+  ctx.lineTo(x + 16, y + 12);
+  ctx.stroke();
+
+  // Draw grain lines randomly
+  ctx.strokeStyle = '#8b5e3c';
+  ctx.lineWidth = 0.5;
+  for (let i = 1; i <= 3; i++) {
+    const yLine = y + i * 4 - 2;
+    ctx.beginPath();
+    ctx.moveTo(x + 2, yLine);
+    ctx.bezierCurveTo(x + 5, yLine - 1, x + 9, yLine + 1, x + 14, yLine - 1);
+    ctx.stroke();
+  }
+}
+
+function drawCarpetTile(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  // 16x16 red carpet tile with border pattern
+  ctx.fillStyle = '#b22222';
+  ctx.fillRect(x, y, 16, 16);
+
+  // Border pattern: small gold diamonds on edges
+  ctx.strokeStyle = '#d4af37';
+  ctx.lineWidth = 1;
+  // Draw diamond shapes at corners and edges
+  function diamond(cx: number, cy: number) {
+    ctx.beginPath();
+    ctx.moveTo(cx, cy - 2);
+    ctx.lineTo(cx + 2, cy);
+    ctx.lineTo(cx, cy + 2);
+    ctx.lineTo(cx - 2, cy);
+    ctx.closePath();
+    ctx.stroke();
+  }
+  diamond(x + 3, y + 3);
+  diamond(x + 13, y + 3);
+  diamond(x + 3, y + 13);
+  diamond(x + 13, y + 13);
+  diamond(x + 8, y + 3);
+  diamond(x + 8, y + 13);
+  diamond(x + 3, y + 8);
+  diamond(x + 13, y + 8);
+}
+
+function drawCobblestoneTile(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  // 16x16 cobblestone tile with irregular circles
+  ctx.fillStyle = '#5a5a5a';
+  ctx.fillRect(x, y, 16, 16);
+
+  // Draw irregular cobblestones as circles with shading
+  const stones = [
+    { cx: x + 5, cy: y + 5, r: 4 },
+    { cx: x + 11, cy: y + 6, r: 3 },
+    { cx: x + 7, cy: y + 11, r: 3.5 },
+    { cx: x + 12, cy: y + 12, r: 3 },
+  ];
+  stones.forEach(({ cx, cy, r }) => {
+    // base stone
+    const grad = ctx.createRadialGradient(cx - 1, cy - 1, r * 0.3, cx, cy, r);
+    grad.addColorStop(0, '#8c8c8c');
+    grad.addColorStop(1, '#4a4a4a');
+    ctx.fillStyle = grad;
+    ctx.beginPath();
+    ctx.ellipse(cx, cy, r, r * 0.7, Math.random() * 0.3, 0, Math.PI * 2);
+    ctx.fill();
+    // stone edge
+    ctx.strokeStyle = '#3a3a3a';
+    ctx.lineWidth = 1;
+    ctx.beginPath();
+    ctx.ellipse(cx, cy, r, r * 0.7, Math.random() * 0.3, 0, Math.PI * 2);
+    ctx.stroke();
+  });
+}
+
+// Map room types to floor tile drawing functions
+const floorTileDrawers: Record<string, (ctx: CanvasRenderingContext2D, x: number, y: number) => void> = {
+  'Dungeon': drawCobblestoneTile,
+  'Library': drawCarpetTile,
+  'Watchtower': drawWoodTile,
+  'Castle': drawStoneTile,
+  // default fallback
+  'Default': drawStoneTile,
+};
+
+/**
+ * Draw tiled floor for a room using 16x16 tiles.
+ * @param ctx CanvasRenderingContext2D
+ * @param bounds Room bounds {x, y, w, h}
+ * @param roomType string room type to select floor tile pattern
+ */
+function drawTiledFloor(ctx: CanvasRenderingContext2D, bounds: { x: number; y: number; w: number; h: number }, roomType: string) {
+  const tileDrawer = floorTileDrawers[roomType] || floorTileDrawers['Default'];
+  const tileSize = 16;
+  const cols = Math.ceil(bounds.w / tileSize);
+  const rows = Math.ceil(bounds.h / tileSize);
+  for (let row = 0; row < rows; row++) {
+    for (let col = 0; col < cols; col++) {
+      const tx = bounds.x + col * tileSize;
+      const ty = bounds.y + row * tileSize;
+      tileDrawer(ctx, tx, ty);
+    }
+  }
+}
+
+// ─── Modified drawRoom to use drawTiledFloor ───────────────────────
+
 function drawRoom(ctx: CanvasRenderingContext2D, room: Room, frame: number) {
-  const { x, y, w, h } = room.bounds;
-  // Draw floor base color
-  ctx.fillStyle = '#444';
-  ctx.fillRect(x, y, w, h);
+  const { x, y, w, h } = room.bounds;
+
+  // Draw floor with tile pattern based on room type
+  drawTiledFloor(ctx, { x, y, w, h }, room.type);
+
   // Draw walls
-  ctx.strokeStyle = '#222';
-  ctx.lineWidth = 2;
-  ctx.strokeRect(x, y, w, h);
+  ctx.strokeStyle = '#222222';
+  ctx.lineWidth = 2;
+  ctx.strokeRect(x, y, w, h);
+
+  // Existing particle effects and other room decorations remain unchanged
+  // (No changes here - floor rendering only)
 }
+
